CustomField.formula:
if( DATEVALUE(CreatedDate) >= DATE(2019,02,09), 
    If( Credit_Note_Issued__c && NOT(Paid__c), 
        Invoice_Amount__c - Credit_Note__c + Refund_Amount__c -  Paid_Amount_Applied__c +  Paid_Amount_Returned__c ,
        Invoice_Amount__c - Amount_Paid__c + Refund_Amount__c -  Paid_Amount_Applied__c +  Paid_Amount_Returned__c
       ),
       If( Credit_Note_Issued__c && NOT(Paid__c), 
         Invoice_Amount__c - Credit_Note__c + Refund_Amount__c,
         Order__r.Due_Amount__c)

)
